#include <iostream>
#include <iomanip>
#include <cmath>

using namespace std;

double compute(int n) {
    double res = cos(n);
    for (int i = n - 1; i >= 1; --i) {
        res = cos(i + res);
    }
    return res;
}

int main() {
    int n;
    cin >> n;
    double ans = compute(n);
    cout << fixed << setprecision(3) << ans << endl;
    return 0;
}
